#!/usr/bin/env bun
/* global Bun, console, process */

import dgram from 'node:dgram';
import { performance } from 'node:perf_hooks';

const BWF2_SIZE = 128;
const FLOW_HEADER_SIZE = 10;
const FLOW_FLAGS_FORK_RACE_FOLD_VENT = 0x0f;

function argValue(name, fallback) {
  const index = process.argv.indexOf(`--${name}`);
  if (index >= 0 && process.argv[index + 1]) {
    return process.argv[index + 1];
  }
  const prefixed = process.argv
    .slice(2)
    .find((value) => value.startsWith(`--${name}=`));
  return prefixed?.slice(name.length + 3) ?? fallback;
}

function numberArg(name, fallback) {
  const parsed = Number.parseInt(argValue(name, `${fallback}`), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

const cli = {
  host: argValue('host', '127.0.0.1'),
  httpPort: numberArg('http-port', 8886),
  udpPort: numberArg('udp-port', 9086),
  path: argValue('path', '/.aeon/fib20-rf?n=20&repetitions=1'),
  requests: numberArg('requests', 500),
  timeoutMs: numberArg('timeout-ms', 1000),
  mode: argValue('mode', 'all'),
};

if (!['all', 'fastest', 'http', 'udp', 'flow', 'aeon-flow'].includes(cli.mode)) {
  throw new Error('--mode must be all|http|udp');
}

function encodeFlowFrame(streamId, sequence, payload) {
  const payloadBytes = Buffer.from(payload);
  if (payloadBytes.length > 0x00ff_ffff) {
    throw new Error('payload exceeds 24-bit Aeon Flow frame length');
  }
  const frame = Buffer.alloc(FLOW_HEADER_SIZE + payloadBytes.length);
  frame.writeUInt16BE(streamId, 0);
  frame.writeUInt32BE(sequence, 2);
  frame[6] = FLOW_FLAGS_FORK_RACE_FOLD_VENT;
  frame[7] = (payloadBytes.length >> 16) & 0xff;
  frame[8] = (payloadBytes.length >> 8) & 0xff;
  frame[9] = payloadBytes.length & 0xff;
  payloadBytes.copy(frame, FLOW_HEADER_SIZE);
  return frame;
}

function decodeFlowFrame(bytes) {
  if (bytes.length < FLOW_HEADER_SIZE) {
    throw new Error('buffer smaller than Aeon Flow header');
  }
  const payloadLength = (bytes[7] << 16) | (bytes[8] << 8) | bytes[9];
  if (bytes.length < FLOW_HEADER_SIZE + payloadLength) {
    throw new Error('incomplete Aeon Flow payload');
  }
  return bytes.subarray(FLOW_HEADER_SIZE, FLOW_HEADER_SIZE + payloadLength);
}

function assertBwf2(bytes, transport) {
  if (bytes.length !== BWF2_SIZE) {
    throw new Error(`${transport} returned ${bytes.length} bytes, expected ${BWF2_SIZE}`);
  }
  if (bytes[0] !== 0x42 || bytes[1] !== 0x57 || bytes[2] !== 0x46 || bytes[3] !== 0x32) {
    throw new Error(`${transport} did not return BWF2 magic`);
  }
}

function stats(samples) {
  const sorted = [...samples].sort((left, right) => left - right);
  const n = sorted.length;
  const quantile = (p) => sorted[Math.floor((n - 1) * p)] ?? 0;
  const mean = sorted.reduce((sum, value) => sum + value, 0) / Math.max(1, n);
  const variance =
    n > 1
      ? sorted.reduce((sum, value) => {
          const delta = value - mean;
          return sum + delta * delta;
        }, 0) /
        (n - 1)
      : 0;
  return {
    n,
    p50_us: quantile(0.5),
    p95_us: quantile(0.95),
    p99_us: quantile(0.99),
    mean_us: mean,
    variance_us2: variance,
    min_us: sorted[0] ?? 0,
    max_us: sorted[n - 1] ?? 0,
  };
}

async function requestHttp() {
  const separator = cli.path.includes('?') ? '&' : '?';
  const response = await fetch(
    `http://${cli.host}:${cli.httpPort}${cli.path}${separator}format=bwf2`,
    { signal: AbortSignal.timeout(cli.timeoutMs) }
  );
  if (!response.ok) {
    throw new Error(`http returned ${response.status}`);
  }
  const bytes = Buffer.from(await response.arrayBuffer());
  assertBwf2(bytes, 'http');
  return bytes;
}

function makeUdpClient() {
  const socket = dgram.createSocket('udp4');
  const requestFrame = encodeFlowFrame(1, 0, cli.path);
  return {
    request(sequence) {
      return new Promise((resolve, reject) => {
        const timer = setTimeout(() => {
          socket.off('message', onMessage);
          reject(new Error('udp timeout'));
        }, cli.timeoutMs);
        const onMessage = (message) => {
          clearTimeout(timer);
          try {
            const payload = decodeFlowFrame(message);
            assertBwf2(payload, 'udp');
            resolve(payload);
          } catch (error) {
            reject(error);
          }
        };
        socket.once('message', onMessage);
        requestFrame.writeUInt32BE(sequence, 2);
        socket.send(requestFrame, cli.udpPort, cli.host);
      });
    },
    close() {
      socket.close();
    },
  };
}

async function main() {
  const udp = makeUdpClient();
  const httpTimes = [];
  const udpTimes = [];
  const fastestTimes = [];
  let httpWins = 0;
  let udpWins = 0;

  try {
    for (let index = 0; index < cli.requests; index += 1) {
      let httpUs = Number.POSITIVE_INFINITY;
      let udpUs = Number.POSITIVE_INFINITY;

      if (!['udp', 'flow', 'aeon-flow'].includes(cli.mode)) {
        const started = performance.now();
        await requestHttp();
        httpUs = (performance.now() - started) * 1000;
        httpTimes.push(httpUs);
      }

      if (cli.mode !== 'http') {
        const started = performance.now();
        await udp.request(index + 1);
        udpUs = (performance.now() - started) * 1000;
        udpTimes.push(udpUs);
      }

      if (httpUs <= udpUs) {
        httpWins += 1;
      } else {
        udpWins += 1;
      }
      fastestTimes.push(Math.min(httpUs, udpUs));
    }
  } finally {
    udp.close();
  }

  console.log(
    JSON.stringify(
      {
        engine: 'bun-fetch-dgram',
        requests: cli.requests,
        http: stats(httpTimes.length > 0 ? httpTimes : fastestTimes),
        udp: stats(udpTimes.length > 0 ? udpTimes : fastestTimes),
        fastest: stats(fastestTimes),
        http_wins: httpWins,
        udp_wins: udpWins,
      },
      null,
      2
    )
  );
}

main().catch((error) => {
  process.stderr.write(`${error instanceof Error ? error.stack ?? error.message : error}\n`);
  process.exitCode = 1;
});
